/**
 * Unit tests for code-comment-glyph-warn PostToolUse hook.
 *
 * Verifies the hook warns on non-vocabulary emoji in code comments
 * and silently passes when comments are clean, when the file isn't
 * a code file, or when the tool isn't Edit/Write.
 *
 * @hook PostToolUse (Edit|Write)
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { codeCommentGlyphWarn } from '../../posttool/code-comment-glyph-warn.js';
import { createTestContext } from '../fixtures/test-context.js';
import type { HookInput } from '../../types.js';

let ctx: ReturnType<typeof createTestContext>;

function makeWriteInput(file_path: string, content: string): HookInput {
  return {
    tool_name: 'Write',
    session_id: 'test',
    tool_input: { file_path, content },
  } as unknown as HookInput;
}

function makeEditInput(file_path: string, new_string: string): HookInput {
  return {
    tool_name: 'Edit',
    session_id: 'test',
    tool_input: { file_path, old_string: '', new_string },
  } as unknown as HookInput;
}

describe('codeCommentGlyphWarn', () => {
  beforeEach(() => {
    ctx = createTestContext();
    vi.clearAllMocks();
  });

  test('silent on non-code file extensions (Markdown)', () => {
    const result = codeCommentGlyphWarn(
      makeWriteInput('docs/README.md', '<!-- 🎉 sparkles -->'),
      ctx,
    );
    expect(result.suppressOutput).toBe(true);
  });

  test('silent on non-Edit/Write tool', () => {
    const input = {
      tool_name: 'Read',
      session_id: 'test',
      tool_input: { file_path: 'x.ts' },
    } as unknown as HookInput;
    const result = codeCommentGlyphWarn(input, ctx);
    expect(result.suppressOutput).toBe(true);
  });

  test('silent when comments contain only vocabulary glyphs', () => {
    // ✅ is in vocab (white check mark, U+2705)
    const content = `
function foo() {
  // ✅ This check passes
  return true;
}
`;
    const result = codeCommentGlyphWarn(makeWriteInput('src/foo.ts', content), ctx);
    expect(result.suppressOutput).toBe(true);
  });

  test('warns when comment contains non-vocabulary glyph', () => {
    // 🎉 (party popper, U+1F389) is NOT in the vocab
    const content = `
function foo() {
  // 🎉 Yay we did it
  return true;
}
`;
    const result = codeCommentGlyphWarn(makeWriteInput('src/foo.ts', content), ctx);
    expect(result.systemMessage).toContain('[visual-style]');
    expect(result.systemMessage).toContain('src/foo.ts');
    expect(result.systemMessage).toContain('🎉');
  });

  test('warns on block comment with decorative glyph', () => {
    const content = `
/**
 * 🚀 Launching the rocket
 */
export function go() {}
`;
    const result = codeCommentGlyphWarn(makeWriteInput('src/go.ts', content), ctx);
    expect(result.systemMessage).toContain('🚀');
  });

  test('warns on Python # comment', () => {
    const content = `
def foo():
    # 🎊 confetti
    return 42
`;
    const result = codeCommentGlyphWarn(makeWriteInput('src/foo.py', content), ctx);
    expect(result.systemMessage).toContain('🎊');
  });

  test('Edit input flagged via new_string', () => {
    const result = codeCommentGlyphWarn(
      makeEditInput('src/bar.ts', '// ✨ sparkle\nconst x = 1;'),
      ctx,
    );
    expect(result.systemMessage).toContain('✨');
  });

  test('silent on shebang (not a real comment)', () => {
    const content = `#!/usr/bin/env node
const x = 1;
`;
    const result = codeCommentGlyphWarn(makeWriteInput('src/cli.js', content), ctx);
    expect(result.suppressOutput).toBe(true);
  });

  test('does not flag emoji in string literals (only comment lines)', () => {
    const content = `
function foo() {
  return "🎉";  // plain comment
}
`;
    const result = codeCommentGlyphWarn(makeWriteInput('src/foo.ts', content), ctx);
    // The comment regex matches lines that START with //, so a string
    // literal followed by a clean // comment on the same line is not
    // flagged. This is the desired behavior — strings should not be
    // false-positive sources. Hook is line-based, not AST-based, but
    // correctly conservative on this case.
    expect(result.suppressOutput).toBe(true);
  });

  test('never blocks (continue is true)', () => {
    const content = '// 🚀 launching\n';
    const result = codeCommentGlyphWarn(makeWriteInput('src/foo.ts', content), ctx);
    expect(result.continue).toBe(true);
  });
});
